function findLucky(arr) {
    const freq = {};
    for (const num of arr) {
        if (!freq[num]) {
            freq[num] = 0;
        }
        freq[num]++;
    }
    let maxLucky = -1;
    for (const [num, count] of Object.entries(freq)) {
        if ( parseInt(num) === count) {
            maxLucky = Math.max(maxLucky, parseInt(num));
        }
    }
    return maxLucky;
}
```

